  1→import { detectRoomFaces } from '@/geometry/roomDetection';
  2→import { distanceToSegment } from '@/geometry/line';
  3→import { add, distance, midpoint, normalize, perpendicular, scale, subtract } from '@/geometry/point';
  4→import { pointInPolygon } from '@/geometry/polygon';
  5→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  6→import { formatMeasurement } from './format';
  7→
  8→const EPSILON = 1e-6;
  9→const WALL_DIMENSION_GAP = 300;
 10→const ROOM_DIMENSION_INSET = 180;
 11→const OVERALL_CHAIN_GAP = 500;
 12→const OVERALL_TOTAL_GAP = 900;
 13→const ARROW_SIZE = 80;
 14→const VALUE_MERGE_TOLERANCE = 5;
 15→const MIN_DIMENSION_LENGTH = 100;
 16→
 17→function normalizeTextAngle(angleDeg) {
 18→  return angleDeg > 90 || angleDeg < -90 ? angleDeg + 180 : angleDeg;
 19→}
 20→
 21→function createArrowHead(tip, direction, size = ARROW_SIZE) {
 22→  const dir = normalize(direction);
 23→  const normal = perpendicular(dir);
 24→  const back = scale(dir, -size);
 25→  const side = scale(normal, size * 0.45);
 26→  return {
 27→    tip,
 28→    left: add(add(tip, back), side),
 29→    right: add(add(tip, back), scale(side, -1)),
 30→  };
 31→}
 32→
 33→function buildAlignedFigure(startPoint, endPoint, offset) {
 34→  const direction = normalize(subtract(endPoint, startPoint));
 35→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) return null;
 36→
 37→  const normal = perpendicular(direction);
 38→  const offsetVector = scale(normal, offset);
 39→  const lineStart = add(startPoint, offsetVector);
 40→  const lineEnd = add(endPoint, offsetVector);
 41→  const angle = normalizeTextAngle(Math.atan2(direction.y, direction.x) * (180 / Math.PI));
 42→
 43→  return {
 44→    lineStart,
 45→    lineEnd,
 46→    extensionLines: [
 47→      { start: startPoint, end: lineStart },
 48→      { start: endPoint, end: lineEnd },
 49→    ],
 50→    textPosition: midpoint(lineStart, lineEnd),
 51→    textAngle: angle,
 52→    measurement: distance(startPoint, endPoint),
 53→    direction,
 54→  };
 55→}
 56→
 57→function buildHorizontalFigure(startPoint, endPoint, offset) {
 58→  const left = startPoint.x <= endPoint.x ? startPoint : endPoint;
 59→  const right = left === startPoint ? endPoint : startPoint;
 60→  const y = (startPoint.y + endPoint.y) / 2 + offset;
 61→  const lineStart = { x: left.x, y };
 62→  const lineEnd = { x: right.x, y };
 63→
 64→  return {
 65→    lineStart,
 66→    lineEnd,
 67→    extensionLines: [
 68→      { start: left, end: lineStart },
 69→      { start: right, end: lineEnd },
 70→    ],
 71→    textPosition: midpoint(lineStart, lineEnd),
 72→    textAngle: 0,
 73→    measurement: Math.abs(endPoint.x - startPoint.x),
 74→    direction: { x: 1, y: 0 },
 75→  };
 76→}
 77→
 78→function buildVerticalFigure(startPoint, endPoint, offset) {
 79→  const top = startPoint.y <= endPoint.y ? startPoint : endPoint;
 80→  const bottom = top === startPoint ? endPoint : startPoint;
 81→  const x = (startPoint.x + endPoint.x) / 2 + offset;
 82→  const lineStart = { x, y: top.y };
 83→  const lineEnd = { x, y: bottom.y };
 84→
 85→  return {
 86→    lineStart,
 87→    lineEnd,
 88→    extensionLines: [
 89→      { start: top, end: lineStart },
 90→      { start: bottom, end: lineEnd },
 91→    ],
 92→    textPosition: midpoint(lineStart, lineEnd),
 93→    textAngle: 90,
 94→    measurement: Math.abs(endPoint.y - startPoint.y),
 95→    direction: { x: 0, y: 1 },
 96→  };
 97→}
 98→
 99→export function createDimensionFigure({
100→  id,
101→  startPoint,
102→  endPoint,
103→  mode = 'aligned',
104→  offset = 0,
105→  label,
106→  source = 'manual',
107→  sourceType = null,
108→  sourceId = null,
109→}) {
110→  let core = null;
111→
112→  if (mode === 'horizontal') core = buildHorizontalFigure(startPoint, endPoint, offset);
113→  else if (mode === 'vertical') core = buildVerticalFigure(startPoint, endPoint, offset);
114→  else core = buildAlignedFigure(startPoint, endPoint, offset);
115→
116→  if (!core || core.measurement < MIN_DIMENSION_LENGTH) return null;
117→
118→  const lineDirection = normalize(subtract(core.lineEnd, core.lineStart));
119→  const startArrow = createArrowHead(core.lineStart, lineDirection);
120→  const endArrow = createArrowHead(core.lineEnd, scale(lineDirection, -1));
121→
122→  return {
123→    id,
124→    type: 'dimension',
125→    source,
126→    sourceType,
127→    sourceId,
128→    mode,
129→    measurement: core.measurement,
130→    label: label || formatMeasurement(core.measurement),
131→    lineStart: core.lineStart,
132→    lineEnd: core.lineEnd,
133→    extensionLines: core.extensionLines,
134→    arrowheads: [startArrow, endArrow],
135→    text: {
136→      position: core.textPosition,
137→      angle: core.textAngle,
138→      value: label || formatMeasurement(core.measurement),
139→    },
140→    segments: [
141→      { start: core.lineStart, end: core.lineEnd },
142→      ...core.extensionLines,
143→      { start: startArrow.tip, end: startArrow.left },
144→      { start: startArrow.tip, end: startArrow.right },
145→      { start: endArrow.tip, end: endArrow.left },
146→      { start: endArrow.tip, end: endArrow.right },
147→    ],
148→  };
149→}
150→
151→function isInsideAnyFace(point, faces) {
152→  return faces.some((face) => pointInPolygon(point, face.points));
153→}
154→
155→function pickWallDimensionFigure(renderWall, faces, wallId) {
156→  const offset = renderWall.thickness / 2 + WALL_DIMENSION_GAP;
157→  const negative = createDimensionFigure({
158→    id: `wall-dim-${wallId}-neg`,
159→    startPoint: renderWall.start,
160→    endPoint: renderWall.end,
161→    mode: 'aligned',
162→    offset: -offset,
163→    source: 'derived',
164→    sourceType: 'wall',
165→    sourceId: wallId,
166→  });
167→  if (!negative) return null;
168→  if (!faces.length) return negative;
169→
170→  const positive = createDimensionFigure({
171→    id: `wall-dim-${wallId}-pos`,
172→    startPoint: renderWall.start,
173→    endPoint: renderWall.end,
174→    mode: 'aligned',
175→    offset,
176→    source: 'derived',
177→    sourceType: 'wall',
178→    sourceId: wallId,
179→  });
180→  if (!positive) return negative;
181→
182→  const negativeInside = isInsideAnyFace(negative.text.position, faces);
183→  const positiveInside = isInsideAnyFace(positive.text.position, faces);
184→
185→  if (negativeInside && !positiveInside) return positive;
186→  if (positiveInside && !negativeInside) return negative;
187→  return negative;
188→}
189→
190→export function buildWallDimensionFigures(walls = [], columns = []) {
191→  const faces = detectRoomFaces(walls, columns || []);
192→
193→  return walls
194→    .map((wall) => {
195→      const renderWall = getWallRenderData(wall, columns || []).renderWall;
196→      return pickWallDimensionFigure(renderWall, faces, wall.id);
197→    })
198→    .filter(Boolean);
199→}
