  1→import { add, subtract, scale, dot, normalize, perpendicular, distance } from './point';
  2→import { nearestPointOnSegment } from './line';
  3→import { columnOutline, columnFaces, columnCenterlines, columnCenter, columnAxes } from './columnGeometry';
  4→
  5→const EPSILON = 1e-6;
  6→const CENTERLINE_ALIGNMENT_THRESHOLD = 0.92;
  7→
  8→function makeOutline(start, end, thickness) {
  9→  const dir = normalize(subtract(end, start));
 10→  const perp = perpendicular(dir);
 11→  const halfThick = thickness / 2;
 12→  const offset = scale(perp, halfThick);
 13→
 14→  return [
 15→    add(start, offset),
 16→    add(end, offset),
 17→    subtract(end, offset),
 18→    subtract(start, offset),
 19→  ];
 20→}
 21→
 22→function findColumn(columns, columnId) {
 23→  return (columns || []).find((column) => column.id === columnId) || null;
 24→}
 25→
 26→function raySegmentIntersection(origin, direction, start, end) {
 27→  const segment = subtract(end, start);
 28→  const cross = direction.x * segment.y - direction.y * segment.x;
 29→
 30→  if (Math.abs(cross) < EPSILON) return null;
 31→
 32→  const delta = subtract(start, origin);
 33→  const t = (delta.x * segment.y - delta.y * segment.x) / cross;
 34→  const u = (delta.x * direction.y - delta.y * direction.x) / cross;
 35→
 36→  if (t < -EPSILON || u < -EPSILON || u > 1 + EPSILON) return null;
 37→
 38→  return {
 39→    t,
 40→    point: add(origin, scale(direction, Math.max(0, t))),
 41→  };
 42→}
 43→
 44→function findTrimPoint(origin, otherPoint, attachment, columns) {
 45→  if (!attachment?.columnId) return { ...origin };
 46→
 47→  const column = findColumn(columns, attachment.columnId);
 48→  if (!column) return { ...origin };
 49→
 50→  const direction = normalize(subtract(otherPoint, origin));
 51→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) {
 52→    return { ...origin };
 53→  }
 54→
 55→  const polygon = columnOutline(column);
 56→  let best = null;
 57→
 58→  for (let i = 0; i < polygon.length; i += 1) {
 59→    const hit = raySegmentIntersection(origin, direction, polygon[i], polygon[(i + 1) % polygon.length]);
 60→    if (!hit) continue;
 61→    if (!best || hit.t < best.t) {
 62→      best = hit;
 63→    }
 64→  }
 65→
 66→  return best ? best.point : { ...origin };
 67→}
 68→
 69→function cloneAttachment(attachment) {
 70→  return attachment ? { ...attachment } : null;
 71→}
 72→
 73→function rankCandidate(current, candidate) {
 74→  if (!current) return true;
 75→  if (candidate.priority !== current.priority) return candidate.priority < current.priority;
 76→  return candidate.distance < current.distance;
 77→}
 78→
 79→function setBestCandidate(best, candidate) {
 80→  if (!candidate) return best;
 81→  if (!rankCandidate(best, candidate)) return best;
 82→  return candidate;
 83→}
 84→
 85→function buildFaceAttachment(column, face, point) {
 86→  const offset = dot(subtract(point, face.midpoint), face.tangent);
 87→  return {
 88→    kind: 'column',
 89→    columnId: column.id,
 90→    featureType: 'face',
 91→    featureIndex: face.index,
 92→    offset,
 93→  };
 94→}
 95→
 96→function buildCenterlineAttachment(column, centerline, point) {
 97→  const center = columnCenter(column);
 98→  return {
 99→    kind: 'column',
100→    columnId: column.id,
101→    featureType: 'centerline',
102→    featureIndex: centerline.index,
103→    offset: dot(subtract(point, center), centerline.axis),
104→  };
105→}
