107→export function resolveColumnAttachmentPoint(column, attachment) {
108→  if (!column || !attachment) return null;
109→
110→  if (attachment.featureType === 'corner') {
111→    const corners = columnOutline(column);
112→    return corners[attachment.featureIndex] ? { ...corners[attachment.featureIndex] } : null;
113→  }
114→
115→  if (attachment.featureType === 'face') {
116→    const face = columnFaces(column).find((entry) => entry.index === attachment.featureIndex);
117→    if (!face) return null;
118→    const clamped = Math.max(-face.length / 2, Math.min(face.length / 2, attachment.offset || 0));
119→    return add(face.midpoint, scale(face.tangent, clamped));
120→  }
121→
122→  if (attachment.featureType === 'centerline') {
123→    const centerline = columnCenterlines(column).find((entry) => entry.index === attachment.featureIndex);
124→    if (!centerline) return null;
125→    return add(columnCenter(column), scale(centerline.axis, attachment.offset || 0));
126→  }
127→
128→  return null;
129→}
130→
131→export function syncWallAttachmentPoints(wall, columns = []) {
132→  let nextWall = { ...wall };
133→
134→  for (const endpoint of ['start', 'end']) {
135→    const attachmentKey = `${endpoint}Attachment`;
136→    const attachment = nextWall[attachmentKey];
137→    if (!attachment) continue;
138→
139→    const column = findColumn(columns, attachment.columnId);
140→    if (!column) {
141→      nextWall = { ...nextWall, [attachmentKey]: null };
142→      continue;
143→    }
144→
145→    const point = resolveColumnAttachmentPoint(column, attachment);
146→    if (!point) {
147→      nextWall = { ...nextWall, [attachmentKey]: null };
148→      continue;
149→    }
150→
151→    nextWall = {
152→      ...nextWall,
153→      [endpoint]: point,
154→      [attachmentKey]: cloneAttachment(attachment),
155→    };
156→  }
157→
158→  return nextWall;
159→}
160→
161→export function detachColumnAttachments(wall, columns = [], columnId) {
162→  const syncedWall = syncWallAttachmentPoints(wall, columns);
163→  let nextWall = syncedWall;
164→
165→  for (const endpoint of ['start', 'end']) {
166→    const attachmentKey = `${endpoint}Attachment`;
167→    if (nextWall[attachmentKey]?.columnId !== columnId) continue;
168→    nextWall = {
169→      ...nextWall,
170→      [attachmentKey]: null,
171→    };
172→  }
173→
174→  return nextWall;
175→}
