 23→  const { point: projected } = nearestPointOnSegment(point, start, end);
 24→  const dx = projected.x - point.x;
 25→  const dy = projected.y - point.y;
 26→  if (dx * dx + dy * dy > tolerance * tolerance) return null;
 27→  return Math.max(0, Math.min(1, t));
