 1→import { createAnnotationSettings } from '@/domain/models';
 2→import { buildManualDimensionFigures, buildOverallDimensionFigures, buildRoomDimensionFigures, buildWallDimensionFigures, hitTestDimensionFigure } from './dimensions';
 3→import { buildAnnotationTags } from './tags';
 4→
 5→export function resolveAnnotationSettings(floor) {
 6→  return createAnnotationSettings(floor?.annotationSettings || {});
 7→}
 8→
 9→export function buildAnnotationScene(floor) {
10→  if (!floor) {
11→    return {
12→      dimensions: [],
13→      manualDimensions: [],
14→      tags: [],
15→    };
16→  }
17→
18→  const settings = resolveAnnotationSettings(floor);
19→  const manualDimensions = buildManualDimensionFigures(floor.annotations || []);
20→  const derivedDimensions = [
21→    ...(settings.showWallDimensions ? buildWallDimensionFigures(floor.walls || [], floor.columns || []) : []),
22→    ...(settings.showRoomDimensions ? buildRoomDimensionFigures(floor.rooms || []) : []),
23→    ...(settings.showOverallDimensions ? buildOverallDimensionFigures(floor.walls || [], floor.columns || []) : []),
24→  ];
25→
26→  return {
27→    dimensions: [...derivedDimensions, ...manualDimensions],
28→    manualDimensions,
29→    tags: settings.showObjectTags ? buildAnnotationTags(floor) : [],
30→  };
31→}
32→
33→export function getManualAnnotationFigure(floor, annotationId) {
34→  return buildManualDimensionFigures(floor?.annotations || []).find((figure) => figure.id === annotationId) || null;
35→}
36→
37→export function hitTestAnnotation(point, floor, tolerance) {
38→  const manualFigures = buildManualDimensionFigures(floor?.annotations || []);
39→
40→  for (let index = manualFigures.length - 1; index >= 0; index -= 1) {
41→    const figure = manualFigures[index];
42→    if (hitTestDimensionFigure(point, figure, tolerance)) {
43→      return { id: figure.id, type: 'annotation' };
44→    }
45→  }
46→
47→  return null;
48→}
