 1→function Arrowhead({ arrow }) {
 2→  return (
 3→    <polyline
 4→      points={`${arrow.left.x},${arrow.left.y} ${arrow.tip.x},${arrow.tip.y} ${arrow.right.x},${arrow.right.y}`}
 5→      fill="none"
 6→      stroke="var(--color-text-secondary)"
 7→      strokeWidth={1}
 8→      vectorEffect="non-scaling-stroke"
 9→      opacity={0.85}
10→    />
11→  );
12→}
13→
14→function DimensionFigure({ figure }) {
15→  return (
16→    <g key={figure.id}>
17→      {figure.extensionLines.map((line, index) => (
18→        <line
19→          key={`${figure.id}-ext-${index}`}
20→          x1={line.start.x}
21→          y1={line.start.y}
22→          x2={line.end.x}
23→          y2={line.end.y}
24→          stroke="var(--color-text-secondary)"
25→          strokeWidth={1}
26→          vectorEffect="non-scaling-stroke"
27→          opacity={0.55}
28→        />
29→      ))}
30→      <line
31→        x1={figure.lineStart.x}
32→        y1={figure.lineStart.y}
33→        x2={figure.lineEnd.x}
34→        y2={figure.lineEnd.y}
35→        stroke="var(--color-text-secondary)"
36→        strokeWidth={1}
37→        vectorEffect="non-scaling-stroke"
38→        opacity={0.75}
39→      />
40→      {figure.arrowheads.map((arrow, index) => (
41→        <Arrowhead key={`${figure.id}-arrow-${index}`} arrow={arrow} />
42→      ))}
43→      <text
44→        x={figure.text.position.x}
45→        y={figure.text.position.y}
46→        textAnchor="middle"
47→        dominantBaseline="middle"
48→        fill="var(--color-text-secondary)"
49→        fontSize={140}
50→        fontFamily="var(--font-blueprint)"
51→        transform={`rotate(${figure.text.angle}, ${figure.text.position.x}, ${figure.text.position.y})`}
52→        style={{ pointerEvents: 'none' }}
53→      >
54→        {figure.text.value}
55→      </text>
56→    </g>
57→  );
58→}
59→
60→function TagFigure({ tag }) {
61→  const lineHeight = 150;
62→  const startY = tag.position.y - ((tag.textLines.length - 1) * lineHeight) / 2;
63→
64→  return (
65→    <text
66→      key={tag.id}
67→      x={tag.position.x}
68→      y={startY}
69→      textAnchor={tag.textAnchor}
70→      dominantBaseline="middle"
71→      fill="var(--color-text-secondary)"
72→      fontSize={120}
73→      fontFamily="var(--font-blueprint)"
74→      transform={`rotate(${tag.angle || 0}, ${tag.position.x}, ${tag.position.y})`}
75→      style={{ pointerEvents: 'none' }}
76→    >
77→      {tag.textLines.map((line, index) => (
78→        <tspan key={`${tag.id}-line-${index}`} x={tag.position.x} dy={index === 0 ? 0 : lineHeight}>
79→          {line}
80→        </tspan>
81→      ))}
82→    </text>
83→  );
84→}
