86→export default function BlueprintAnnotationLayer({ dimensions = [], tags = [], className = 'annotations' }) {
87→  return (
88→    <g className={className}>
89→      {dimensions.map((figure) => (
90→        <DimensionFigure key={figure.id} figure={figure} />
91→      ))}
92→      {tags.map((tag) => (
93→        <TagFigure key={tag.id} tag={tag} />
94→      ))}
95→    </g>
96→  );
97→}
